from sentence_transformers import SentenceTransformer
import numpy as np

class EmbeddingBackbone:
    def __init__(self, model_name="all-MiniLM-L6-v2", use_onnx=False):
        kwargs = {}
        if use_onnx:
            kwargs = {"backend": "onnx",
                      "model_kwargs": {"provider": "CPUExecutionProvider"}}
        self.model = SentenceTransformer(model_name, **kwargs)
        self.dim = self.model.get_sentence_embedding_dimension()

    def encode(self, texts, batch_size=64):
        return self.model.encode(
            texts, batch_size=batch_size,
            normalize_embeddings=True, show_progress_bar=False
        )

    def similarity(self, emb_a, emb_b):
        return np.dot(emb_a, emb_b.T)

backbone = EmbeddingBackbone()
print(f"Dimension: {backbone.dim}")

import numpy as np

class HomieRetriever:
    def __init__(self, backbone):
        self.backbone = backbone
        self.chunks = []
        self.embeddings = None

    def add_chunks(self, chunks):
        new_embs = self.backbone.encode(chunks)
        self.chunks.extend(chunks)
        if self.embeddings is None:
            self.embeddings = new_embs
        else:
            self.embeddings = np.vstack([self.embeddings, new_embs])

    def query(self, question, top_k=3):
        q_emb = self.backbone.encode([question])[0]
        scores = np.dot(self.embeddings, q_emb)
        top_idx = np.argsort(scores)[::-1][:top_k]
        return [{"chunk": self.chunks[i], "score": float(scores[i])} for i in top_idx]

    def build_context(self, question, top_k=3):
        results = self.query(question, top_k)
        ctx = "\n".join(f"- {r['chunk']}" for r in results)
        return f"Context:\n{ctx}\n\nQuestion: {question}\nAnswer:"

