import math

class EmbeddingBackbone:
    def _word_vector(self, text):
        words = text.lower().split()
        vec = {}
        for w in words:
            vec[w] = vec.get(w, 0) + 1
        return vec

    def _normalize(self, vec):
        mag = math.sqrt(sum(v**2 for v in vec.values()))
        if mag == 0:
            return {}
        return {k: v / mag for k, v in vec.items()}

    def encode(self, texts):
        return [self._normalize(self._word_vector(t)) for t in texts]

    def similarity(self, vec_a, vec_b):
        shared = set(vec_a) & set(vec_b)
        return sum(vec_a[w] * vec_b[w] for w in shared)

